using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.Json;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var apiKey  = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "";
var model   = Environment.GetEnvironmentVariable("OPENAI_MODEL")   ?? "gpt-4o-mini";
var topic   = args.Length > 0
    ? string.Join(' ', args)
    : "recent advances in quantum computing 2026";

Console.WriteLine($"🔬  Research Agent Starting...");
Console.WriteLine($"📌  Topic: {topic}");
Console.WriteLine();

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------
var notebook = new Notebook();

IChatClient client = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient(model).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(WebSearchTool.SearchAsync),
        AIFunctionFactory.Create(WebSearchTool.FetchPageAsync),
        AIFunctionFactory.Create(notebook.AddNote),
        AIFunctionFactory.Create(notebook.GetNotes),
    ],
};

// ---------------------------------------------------------------------------
// Agent loop
// ---------------------------------------------------------------------------
List<ChatMessage> history =
[
    new(ChatRole.System, """
        You are a research agent. Your goal is to thoroughly research the given
        topic using the tools available to you.

        Workflow:
        1. Search the web for relevant information (2-3 searches with varied queries).
        2. Fetch the most promising pages to get detailed content.
        3. Take structured notes on key findings using the note-taking tool.
        4. After gathering enough information, call get_notes to review your notes,
           then produce a final summary.

        Your final answer should be a well-structured research summary with:
        - An overview paragraph
        - Key findings (bulleted)
        - Sources cited
        """),
    new(ChatRole.User, $"Please research the following topic: {topic}"),
];

Console.WriteLine("🤖  Agent is researching (this may take a minute)...\n");

var response = await client.GetResponseAsync(history, chatOptions);

Console.WriteLine("═══════════════════════════════════════════════════════════════");
Console.WriteLine("  RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════════════════════════════");
Console.WriteLine(response.Text);
Console.WriteLine("═══════════════════════════════════════════════════════════════");
Console.WriteLine($"\n📝  Notes collected: {notebook.Count}");

// ---------------------------------------------------------------------------
// Web Search Tool – uses DuckDuckGo HTML search (no API key required)
// ---------------------------------------------------------------------------
static partial class WebSearchTool
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
        },
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description("Search the web for a query and return a list of result titles, snippets, and URLs.")]
    public static async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  🔍  Searching: {query}");
        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var html = await Http.GetStringAsync(
                $"https://html.duckduckgo.com/html/?q={encoded}");

            var results = new List<object>();
            // Parse result blocks from DuckDuckGo HTML response
            foreach (Match m in ResultRegex().Matches(html))
            {
                var url     = WebUtility.HtmlDecode(m.Groups["url"].Value).Trim();
                var title   = StripHtml(WebUtility.HtmlDecode(m.Groups["title"].Value));
                var snippet = StripHtml(WebUtility.HtmlDecode(m.Groups["snippet"].Value));

                if (string.IsNullOrWhiteSpace(title)) continue;

                // DuckDuckGo wraps URLs through a redirect; extract the actual URL
                var actualUrl = ExtractRedirectUrl(url) ?? url;
                results.Add(new { title, snippet, url = actualUrl });
                if (results.Count >= 8) break;
            }

            return results.Count > 0
                ? JsonSerializer.Serialize(results, JsonOptions)
                : "No results found. Try a different query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch the text content of a web page given its URL. Returns the first ~3000 characters of readable text.")]
    public static async Task<string> FetchPageAsync(
        [Description("The URL to fetch")] string url)
    {
        Console.WriteLine($"  🌐  Fetching: {url}");
        try
        {
            var html = await Http.GetStringAsync(url);
            var text = StripHtml(html);

            // Collapse whitespace
            text = Regex.Replace(text, @"\s+", " ").Trim();
            if (text.Length > 3000)
                text = text[..3000] + "…";

            return string.IsNullOrWhiteSpace(text)
                ? "Could not extract readable text from this page."
                : text;
        }
        catch (Exception ex)
        {
            return $"Fetch failed: {ex.Message}";
        }
    }

    // -- helpers --

    private static string StripHtml(string html)
    {
        var text = Regex.Replace(html, @"<script[^>]*>[\s\S]*?</script>", " ", RegexOptions.IgnoreCase);
        text = Regex.Replace(text, @"<style[^>]*>[\s\S]*?</style>", " ", RegexOptions.IgnoreCase);
        text = Regex.Replace(text, @"<[^>]+>", " ");
        return WebUtility.HtmlDecode(text);
    }

    private static string? ExtractRedirectUrl(string url)
    {
        var match = Regex.Match(url, @"[?&]uddg=([^&]+)");
        return match.Success ? WebUtility.UrlDecode(match.Groups[1].Value) : null;
    }

    [GeneratedRegex(
        @"<a[^>]+class=""result__a""[^>]+href=""(?<url>[^""]+)""[^>]*>(?<title>.*?)</a>.*?<a[^>]+class=""result__snippet""[^>]*>(?<snippet>.*?)</a>",
        RegexOptions.Singleline)]
    private static partial Regex ResultRegex();

    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };
}

// ---------------------------------------------------------------------------
// Notebook Tool – structured note-taking
// ---------------------------------------------------------------------------
class Notebook
{
    private readonly List<(string Category, string Content)> _notes = [];

    public int Count => _notes.Count;

    [Description("Add a research note. Use this to record key findings as you research.")]
    public string AddNote(
        [Description("Category such as 'key-finding', 'statistic', 'source', or 'quote'")] string category,
        [Description("The note content")] string content)
    {
        _notes.Add((category, content));
        Console.WriteLine($"  📝  Note added [{category}]: {Truncate(content, 80)}");
        return $"Note #{_notes.Count} saved under '{category}'.";
    }

    [Description("Retrieve all notes taken so far, grouped by category.")]
    public string GetNotes()
    {
        if (_notes.Count == 0) return "No notes taken yet.";

        var sb = new StringBuilder();
        foreach (var group in _notes.GroupBy(n => n.Category))
        {
            sb.AppendLine($"## {group.Key}");
            foreach (var (_, content) in group)
                sb.AppendLine($"- {content}");
            sb.AppendLine();
        }
        return sb.ToString();
    }

    private static string Truncate(string s, int max) =>
        s.Length <= max ? s : s[..(max - 1)] + "…";
}

